void insertAtTail(int val) {
    Node* newNode = new Node(val);
    if (head == nullptr) {
        head = newNode;
        tail = newNode; // set both head and tail
        return;
    }
    tail->next = newNode;
    newNode->prev = tail;
    tail = newNode;
}

